// BTAspectRatio types — Figma source: node 820:3124.

/// Supported aspect ratios for [BTAspectRatio].
enum BTAspectRatioRatio {
  /// 16:9 — landscape widescreen (default).
  r16x9(16 / 9),

  /// 9:16 — portrait / vertical video.
  r9x16(9 / 16),

  /// 1:1 — square.
  r1x1(1 / 1),

  /// 4:5 — portrait photo (Instagram-style).
  r4x5(4 / 5),

  /// 5:4 — landscape photo.
  r5x4(5 / 4);

  const BTAspectRatioRatio(this.value);

  /// Numeric aspect ratio passed to Flutter's [AspectRatio] widget.
  final double value;
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';

import 'aspect_ratio.types.dart';

/// BTAspectRatio — layout utility atom (Figma 820:3124).
///
/// Constrains [child] to a fixed aspect ratio with rounded corners and
/// overflow clipping. The background uses [context.btColor.bg.secondary]
/// so it's visible as a placeholder when no child is provided.
///
/// ```dart
/// // 16:9 image (default ratio)
/// BTAspectRatio(
///   ratio: BTAspectRatioRatio.r16x9,
///   child: Image.network(url, fit: BoxFit.cover),
/// )
///
/// // Square thumbnail
/// BTAspectRatio(
///   ratio: BTAspectRatioRatio.r1x1,
///   child: Image.network(url, fit: BoxFit.cover),
/// )
///
/// // Portrait placeholder (no child)
/// const BTAspectRatio(ratio: BTAspectRatioRatio.r9x16)
/// ```
class BTAspectRatio extends StatelessWidget {
  const BTAspectRatio({
    this.ratio = BTAspectRatioRatio.r16x9,
    this.child,
    super.key,
  });

  /// Aspect ratio constraint applied to the container.
  ///
  /// Defaults to [BTAspectRatioRatio.r16x9].
  final BTAspectRatioRatio ratio;

  /// Optional content to display inside the constrained container.
  /// Should typically be an [Image] or [Widget] that fills its bounds.
  final Widget? child;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radii = context.btRadius;

    return AspectRatio(
      aspectRatio: ratio.value,
      child: ClipRRect(
        borderRadius: BorderRadius.circular(radii.md),
        child: ColoredBox(
          color: colors.bg.secondary,
          child: child,
        ),
      ),
    );
  }
}
